class DeepLinkHandler : Activity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val uri = intent?.data
        if (uri?.scheme == "myapp") {
            when (uri.pathSegments.firstOrNull()) {
                "profile" -> {
                    val userId = uri.pathSegments.getOrNull(1)?.toIntOrNull()
                    startActivity(ProfileActivity.getIntent(this, userId))
                }
                "payment" -> {
                    when (uri.pathSegments.getOrNull(1)) {
                        "confirm" -> startActivity(PaymentConfirmationActivity.getIntent(this))
                        else -> throw IllegalArgumentException("Invalid payment path segment")
                    }
                }
                else -> throw IllegalArgumentException("Invalid deep link path")
            }
        }
    }
